-- ตารางค่าซ่อมแบบรายการย่อย (line item) รายเดือน — ดึงเข้า pivot เดือนต่อเดือน
CREATE TABLE IF NOT EXISTS repair_line_items (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  year int NOT NULL,
  month int NOT NULL,            -- 1-12
  section text NOT NULL,         -- เครื่องจักรบางเลน / เครื่องจักรบ่อตะกั่ว / เครนรถบางเลน ...
  line_item text NOT NULL,       -- รายการย่อย เช่น แพล้นท์คอนกรีต
  sort_order int NOT NULL DEFAULT 0,
  amount numeric NOT NULL DEFAULT 0,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE repair_line_items ENABLE ROW LEVEL SECURITY;
CREATE POLICY "allow all" ON repair_line_items FOR ALL USING (true) WITH CHECK (true);

